// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <string.h>
#define MOD 1000000007
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, len;
        scanf("%d %d", &N, &len);
        char S[1000001];
        scanf("%s", S);
        long long ans = 0;
        for (int R = 1; R <= N; R++) {
            for (int C = 1; C <= N; C++) {
                if (R == C) continue;
                char sig[1000001];
                int idx = 0;
                int x = R, y = C;
                while (x > 0 && y > 0) {
                    if (x > y) {
                        sig[idx++] = 'R';
                        x -= y;
                    } else {
                        sig[idx++] = 'L';
                        y -= x;
                    }
                }
                sig[idx] = '\0';
                if (strncmp(sig, S, len) == 0) {
                    ans = (ans + idx) % MOD;
                }
            }
        }
        printf("%lld\n", ans);
    }
    return 0;
}

